sql:
SELECT user_name
FROM users
WHERE user_id = 0;

SELECT DISTINCT u.user_id, u.user_name
FROM users u
JOIN audit_logs al ON u.user_id = al.user_id;

SELECT financial_indicators.data_source_id, MAX(financial_indicators.value) AS highest_value
FROM financial_indicators
GROUP BY financial_indicators.data_source_id;

SELECT source_id, source_name, source_type, last_updated,
       (SELECT MAX(last_updated) FROM data_sources) AS most_recent_update_date
FROM data_sources;

external_knowledge:
- "sailors" metaphorically represents users;
- "ventured into the deepest waters" metaphorically represents performing actions;
- "latest voyage details" corresponds to the maximum timestamp and the associated action for each user.

- 'high-level personnel' refers to the 'manager' role in the system;
- 'modified internal records' implies an 'UPDATE' action on 'internal' type data sources;
- 'active' corresponds to the user status being 'active'.

sql:
SELECT data_sources.source_name, data_sources.source_description
FROM data_sources
WHERE data_sources.status = 'active';

SELECT u.user_name, u.role, fi.value
FROM users u
CROSS JOIN financial_indicators fi;

SELECT model_id, AVG(quality_score) AS average_quality_rating
FROM data_quality_checks
GROUP BY model_id;
